from dataclasses import dataclass, field

@dataclass
class InterviewFinding:
    participant_id: str       # anonymised (P01, P02...)
    role: str
    pain_point: str           # verbatim quote or close paraphrase
    frequency: str            # "every claim", "weekly", "rare"
    severity: str             # "blocking", "annoying", "minor"
    ai_opportunity: str       # researcher inference — what AI could address
    constraint: str           # what AI must NOT do (from mental model phase)

@dataclass
class DiscoverySynthesis:
    feature_area: str
    findings: list[InterviewFinding] = field(default_factory=list)

    def top_pain_points(self, n: int = 5) -> list[InterviewFinding]:
        severity_rank = {"blocking": 0, "annoying": 1, "minor": 2}
        freq_rank     = {"every claim": 0, "weekly": 1, "rare": 2}
        return sorted(
            self.findings,
            key=lambda f: (severity_rank.get(f.severity, 9), freq_rank.get(f.frequency, 9)),
        )[:n]

    def constraints(self) -> list[str]:
        return list({f.constraint for f in self.findings if f.constraint})

    def opportunities(self) -> list[str]:
        return list({f.ai_opportunity for f in self.findings if f.ai_opportunity})

# Example: 6 interviews with FNOL claims handlers
synthesis = DiscoverySynthesis(feature_area="FNOL Chatbot")

synthesis.findings = [
    InterviewFinding(
        participant_id="P01", role="Senior Claims Handler",
        pain_point="'I spend 10 minutes just copying information from the email into the CRM fields — it's all there, I just have to retype it.'",
        frequency="every claim", severity="blocking",
        ai_opportunity="Pre-fill CRM fields from inbound email / submission text",
        constraint="'Don't auto-submit anything — I need to review before it's saved.'",
    ),
    InterviewFinding(
        participant_id="P02", role="Claims Handler",
        pain_point="'When claimants describe damage vaguely, I have to call them back to get specifics. That call takes 20 minutes on average.'",
        frequency="every claim", severity="blocking",
        ai_opportunity="AI chat captures structured damage description before human handoff",
        constraint="'If the AI gets the damage category wrong, the whole claim goes to the wrong team.'",
    ),
    InterviewFinding(
        participant_id="P03", role="Team Leader",
        pain_point="'My team doesn't know which claims to prioritise — they work FIFO but some are urgent and they can't always tell.'",
        frequency="weekly", severity="blocking",
        ai_opportunity="Urgency triage: surface high-priority claims based on policy type and description",
        constraint="'Urgency decisions affect customer trust — I'd want a human to review any 'urgent' flag before action.'",
    ),
]

print([f.pain_point[:50] for f in synthesis.top_pain_points(2)])
print(synthesis.constraints())
